using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // --- AddItem ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU1", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("SKU1", 1, 5.00m);
        _cart.AddItem("SKU1", 3, 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleSkus_SumsAll()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 2, 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [DataTestMethod]
    [DataRow(null)]
    public void AddItem_NullSku_ThrowsArgumentNullException(string? sku)
    {
        Assert.ThrowsException<ArgumentNullException>(() => _cart.AddItem(sku!, 1, 1.00m));
    }

    [DataTestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRange(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU1", quantity, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("SKU1", 1, -1.00m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("SKU1", 1, 10.00m);
        _cart.AddItem("SKU2", 1, 5.00m);

        _cart.RemoveItem("SKU1");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _cart.RemoveItem(null!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_ZeroPriceItem_ReturnsZero()
    {
        _cart.AddItem("FREE", 5, 0.00m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [DataTestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("SAVE20", 20)]
    [DataRow("HALF", 50)]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int expectedPercent)
    {
        _cart.AddItem("SKU1", 1, 100.00m);

        _cart.ApplyCoupon(code);

        Assert.AreEqual(100.00m - expectedPercent, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedBeforeAddingItems_StillDiscounts()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.AddItem("SKU1", 2, 50.00m);

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }
}

